#include<bits/stdc++.h>
#define data mydata
#define sni set<node>::iterator
#define sdi set<data>::iterator
using namespace std;
int n,m,pre[100010],npre[100010],a[100010],tp[100010],lf[100010],rt[100010],co[100010];
struct modi
{
    int t,pos,pre,val;
    bool operator<(const modi&b)const
    {
        return pre<b.pre;
    }
}md[1000010];
int tp1;
struct query
{
    int t,l,r,ans;
    bool operator<(const query&b)const
    {
        return l<b.l;
    }
}qr[100010];
int tp2,cnt;
bool cmp(query a,query b)
{
    return a.t<b.t;
}
void modify(int pos,int v)
{
    if(npre[pos]==v)
    {
        return;
    }
    md[++tp1]=(modi){++cnt,pos,npre[pos],-1};
    md[++tp1]=(modi){++cnt,pos,npre[pos]=v,1};
}
int lst[200010];
map<int,int> mp;
void prew()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        mp[a[i]]=1;
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&tp[i],&lf[i],&rt[i]);
        if(tp[i]==1)
        {
            scanf("%d",&co[i]);
            mp[co[i]]=1;
        }
    }
    map<int,int>::iterator it,it1;
    for(it=mp.begin(),it1=it,++it1;it1!=mp.end();++it,++it1)
    {
        it1->second+=it->second;
    }
    for(int i=1;i<=n;i++)
    {
        a[i]=mp[a[i]];
    }
    for(int i=1;i<=m;i++)
    {
        if(tp[i]==1)
        {
            co[i]=mp[co[i]];
        }
    }
    for(int i=1;i<=n;i++)
    {
        pre[i]=lst[a[i]];
        lst[a[i]]=i;
    }
    for(int i=1;i<=n;i++)
    {
        npre[i]=pre[i];
    }
}
struct data
{
    int l,r,x;
    bool operator<(const data&b)const
    {
        return r<b.r;
    }
};
set<data> s;
struct node
{
    int l,r;
    bool operator<(const node&b)const
    {
        return r<b.r;
    }
};
set<node> c[200010];
set<int> bd;
void split(int mid)
{
    sdi it=s.lower_bound((data){0,mid,0});
    data p=(*it);
    if(p.r==mid)
    {
        return;
    }
    s.erase(p);
    s.insert((data){p.l,mid,p.x});
    s.insert((data){mid+1,p.r,p.x});
    c[p.x].erase((node){p.l,p.r});
    c[p.x].insert((node){p.l,mid});
    c[p.x].insert((node){mid+1,p.r});
}
void del(sdi it)
{
    bd.insert(it->l);
    sni it1,it2;
    it1=it2=c[it->x].find((node){it->l,it->r});
    ++it2;
    if(it2!=c[it->x].end())
    {
        bd.insert(it2->l);
    }
    c[it->x].erase(it1);
    s.erase(it);
}
void insert(data x)
{
    s.insert(x);
    sni it=c[x.x].insert((node){x.l,x.r}).first;
    ++it;
    if(it!=c[x.x].end())
    {
        bd.insert(it->l);
    }
}
void stv(int l,int r,int x)
{
    if(l!=1)
    {
        split(l-1);
    }
    split(r);
    int p=l;
    while(p!=r+1)
    {
        sdi it=s.lower_bound((data){0,p,0});
        p=it->r+1;
        del(it);
    }
    insert((data){l,r,x});
    for(set<int>::iterator it=bd.begin();it!=bd.end();++it)
    {
        sdi it1=s.lower_bound((data){0,*it,0});
        if((*it)!=it1->l)
        {
            modify(*it,(*it)-1);
        }
        else
        {
            sni it2=c[it1->x].lower_bound((node){0,*it});
            if(it2!=c[it1->x].begin())
            {
                --it2;
                modify(*it,it2->r);
            }
            else
            {
                modify(*it,0);
            }
        }
    }
    bd.clear();
}
void ih()
{
    int nc=a[1],cnt=1;
    for(int i=2;i<=n;i++)
    {
        if(nc!=a[i])
        {
            s.insert((data){i-cnt,i-1,nc});
            c[nc].insert((node){i-cnt,i-1});
            nc=a[i];
            cnt=1;
        }
        else
        {
            cnt++;
        }
    }
    s.insert((data){n-cnt+1,n,a[n]});
    c[a[n]].insert((node){n-cnt+1,n});
}
struct fenwick
{
    int a[100010];
    int lowbit(int x)
    {
        return x&-x;
    }
    void add(int x,int v)
    {
        for(int i=x;i<=n;i+=lowbit(i))
        {
            a[i]+=v;
        }
    }
    void update(int x)
    {
        for(int i=x;i<=n;i+=lowbit(i))
        {
            a[i]=0;
        }
    }
    int query(int x)
    {
        int ans=0;
        for(int i=x;i>=1;i-=lowbit(i))
        {
            ans+=a[i];
        }
        return ans;
    }
    void clear()
    {
        for(int i=1;i<=n;i++)
        {
            a[i]=0;
        }
    }
}t;
int srt[100010];
bool cmp1(int a,int b)
{
    return pre[a]<pre[b];
}
void solve(int l1,int r1,int l2,int r2,int L,int R)
{
    if(l1==r1||l2==r2)
    {
        return;
    }
    int mid=(L+R)/2;
    int mid1=l1;
    while(mid1!=r1&&md[mid1+1].t<=mid)
    {
        mid1++;
    }
    int mid2=l2;
    while(mid2!=r2&&qr[mid2+1].t<=mid)
    {
        mid2++;
    }
    solve(l1,mid1,l2,mid2,L,mid);
    solve(mid1,r1,mid2,r2,mid,R);
    if(l1!=mid1&&mid2!=r2)
    {
        sort(md+1+l1,md+1+mid1);
        sort(qr+1+mid2,qr+1+r2);
        for(int i=mid2+1,j=l1+1;i<=r2;i++)
        {
            while(j<=mid1&&md[j].pre<qr[i].l)
            {
                t.add(md[j].pos,md[j].val);
                j++;
            }
            qr[i].ans+=t.query(qr[i].r)-t.query(qr[i].l-1);
        }
        for(int i=l1+1;i<=mid1;i++)
        {
            t.update(md[i].pos);
        }
    }
}
int main()
{
    prew();
    ih();
    for(int i=1;i<=m;i++)
    {
        if(tp[i]==1)
        {
            stv(lf[i],rt[i],co[i]);
        }
        else
        {
            qr[++tp2]=(query){++cnt,lf[i],rt[i],0};
        }
    }
    sort(qr+1,qr+1+tp2);
    for(int i=1;i<=n;i++)
    {
        srt[i]=i;
    }
    sort(srt+1,srt+1+n,cmp1);
    for(int i=1,j=1;i<=tp2;i++)
    {
        while(j<=n&&pre[srt[j]]<qr[i].l)
        {
            t.add(srt[j],1);
            j++;
        }
        qr[i].ans+=t.query(qr[i].r)-t.query(qr[i].l-1);
    }
    t.clear();
    sort(qr+1,qr+1+tp2,cmp);
    solve(0,tp1,0,tp2,0,cnt);
    sort(qr+1,qr+1+tp2,cmp);
    for(int i=1;i<=tp2;i++)
    {
        printf("%d\n",qr[i].ans);
    }
    return 0;
}
